mapper.select:
SELECT s.shape_id, s.shape_user_id, s.doc_id, d.doc_name, d.doc_size, d.doc_suffix, d.type, s.shape_time, s.invalid_time, CASE WHEN s.invalid_time > SYSDATE THEN 0 ELSE 1 END AS shape_state, CASE WHEN s.invalid_time > SYSDATE THEN 1 ELSE 0 END AS isAsh, CASE WHEN d.recycle_status = 1 THEN 0 ELSE 1 END AS isRecovery, CASE WHEN d.doc_status = 3 THEN 0 ELSE 1 END AS isNoSelf FROM doc_bs_shape s LEFT JOIN doc_bs_document d ON d.bus_id = s.doc_id
JOIN ( SELECT doc_id FROM doc_bs_tag_document WHERE tag_id IN
#{item}
) t ON t.doc_id = s.doc_id
WHERE d.is_deleted = 0
AND d.doc_name LIKE '%' || #{docName} || '%'
AND s.shape_user_id IN
#{item}
AND s.shape_time BETWEEN #{shapeTimeTo} AND #{shapeTimeDo}
AND s.invalid_time >= #{date}
AND s.invalid_time < #{date}
AND s.shape_id IN
#{shapeId}
ORDER BY s.shape_time ASC
ORDER BY s.shape_time DESC
ORDER BY s.invalid_time ASC
ORDER BY s.invalid_time DESC
ORDER BY s.shape_time DESC

SELECT s.shape_id, s.shape_type, CASE WHEN s.shape_type = 0 THEN '内部分享' ELSE '外部分享' END AS shapeTypeStr, s.doc_id, d.doc_name, d.doc_size, d.type, d.doc_suffix, s.shape_time, s.shape_preview, s.shape_section, s.invalid_time, CASE WHEN s.invalid_time > SYSDATE THEN 0 ELSE 1 END AS shape_state, CASE WHEN u.doc_id IS NOT NULL OR d.doc_type = 1 THEN 1 ELSE 0 END AS isAsh, CASE WHEN d.recycle_status = 1 THEN 0 ELSE 1 END AS isRecovery, CASE WHEN d.doc_status = 3 THEN 0 ELSE 1 END AS isNoSelf FROM doc_bs_shape s LEFT JOIN doc_bs_document d ON d.bus_id = s.doc_id LEFT JOIN ( SELECT DISTINCT doc_id FROM doc_bs_document_user WHERE is_deleted = 0 AND rel_id IN
#{item}
) u ON u.doc_id = d.bus_id
JOIN ( SELECT doc_id FROM doc_bs_tag_document WHERE tag_id IN
#{item}
) t ON t.doc_id = s.doc_id
WHERE d.is_deleted = 0
AND d.doc_name LIKE '%' || #{docName} || '%'
AND u.name LIKE '%' || #{sharer} || '%'
AND s.shape_time BETWEEN #{shapeTimeTo} AND #{shapeTimeDo}
AND s.invalid_time >= #{date}
AND s.invalid_time < #{date}
AND s.shape_user_id =#{shapeUserId}
AND s.shape_type =#{shapeType}
ORDER BY s.shape_time ASC
ORDER BY s.shape_time DESC
ORDER BY s.invalid_time ASC
ORDER BY s.invalid_time DESC
ORDER BY s.shape_time DESC

SELECT s.shape_id AS id, s.doc_id AS contentId, d.doc_name AS content, CASE WHEN s.invalid_time > SYSDATE THEN 0 ELSE 1 END AS isRead, CASE WHEN d.recycle_status = 1 THEN 0 ELSE 1 END AS isRecovery, CASE WHEN d.doc_status = 3 THEN 0 ELSE 1 END AS isNoSelf FROM doc_bs_shape s LEFT JOIN doc_bs_document d ON d.bus_id = s.doc_id WHERE d.is_deleted = 0 AND s.shape_id IN
#{item}
ORDER BY s.shape_time DESC
